-- CREATED: 03.03.2009 
-- AUTHOR : EMR
-- PURPOSE:
-- this script will change the price code of companies from DIYDDSTD-3 (waive the
-- 3 dollar payroll fee) to DIYDDSTD.  This is due to a bug in the adapters that
-- accidentally reset the price codes after migration.
--
-- This script loads the companies that will be updated.

-- This must be run as PSPADM user.

SET serveroutput ON
SET linesize     500
SET pagesize     1000
SET define       OFF

SPOOL util_load_reset_diy_companies_03052009.log

SELECT USER AS LOGIN_ID FROM DUAL;
SELECT TO_CHAR(SYSDATE, 'MM.DD.YYYY HH24:MI') AS START_TIME FROM DUAL;


PROMPT .
PROMPT Create temporary table that will contain the list of companies to reset ...

DROP TABLE Z_TEMP_DIY_RESET_COMPANY;

CREATE TABLE Z_TEMP_DIY_RESET_COMPANY
(
  SOURCE_COMPANY_ID  VARCHAR2(50) PRIMARY KEY,
  UPDATED_YN_IND     VARCHAR2(10) DEFAULT 'N',
  MODIFIED_DTTM      DATE
);

COMMENT ON TABLE Z_TEMP_DIY_RESET_COMPANY IS
'This table contains a list of DIY companies that will have their price codes reset to standard.  This is to address a bug in the adapters.  To run only on Mar 5 2009';


PROMPT .
PROMPT Load the companies that will have their price codes reset to standard ...

